public int getOffsetFromLocal(long instantLocal) {
    final int initialOffset = getOffset(instantLocal);
    final long adjustedInstant = instantLocal - initialOffset;
    final int adjustedOffset = getOffset(adjustedInstant);

    if (initialOffset != adjustedOffset) {
        if ((initialOffset > adjustedOffset && initialOffset > 0) || (initialOffset < adjustedOffset && initialOffset < 0)) {
            long nextLocalTransition = nextTransition(adjustedInstant);
            if (nextLocalTransition < instantLocal) {
                return adjustedOffset;
            }
        }
        return initialOffset;
    }

    long previousTransitionInstant = previousTransition(adjustedInstant);
    if (previousTransitionInstant < adjustedInstant) {
        int prevOffset = getOffset(previousTransitionInstant);
        if (adjustedInstant - previousTransitionInstant <= prevOffset - initialOffset) {
            return prevOffset;
        }
    }

    return adjustedOffset;
}
